function solve(nums1) {
    const n = nums1.length;

    // Helper function to check if all numbers in an array have the same parity
    const checkParity = (arr) => {
        if (arr.length === 0) return true;
        const parity = Math.abs(arr[0] % 2); // 0 for even, 1 for odd
        for (let i = 1; i < arr.length; i++) {
            if (Math.abs(arr[i] % 2) !== parity) {
                return false;
            }
        }
        return true;
    };

    // We need to check if there exists a construction for all odd OR all even.
    // Since the choice at each index i depends on choices at other indices j,
    // this problem structure suggests exploring possibilities, but the constraints
    // (N <= 100, nums1[i] <= 100) and the nature of the operations (addition/subtraction)
    // hint at a property based on parities.

    // Let P_i be the parity of nums1[i] (0 for even, 1 for odd).
    // The choices for nums2[i] are:
    // 1. nums2[i] = nums1[i] (Parity = P_i)
    // 2. nums2[i] = nums1[i] - nums1[j] (Parity = P_i XOR P_j)

    // We want all nums2[i] to have the same parity K (K=0 for even, K=1 for odd).

    // Iterate over all possible target parities K (0 or 1)
    for (let K = 0; K <= 1; K++) {
        // Try to construct nums2 such that all elements are K mod 2.
        // This is a constraint satisfaction problem. Since N is small (<= 100),
        // we might look for a greedy or DP approach, but let's analyze the dependencies.

        // The choice at i depends on which j we pick for subtraction, or if we pick nums1[i].

        // Case 1: Target Parity K = 0 (All Even)
        // Case 2: Target Parity K = 1 (All Odd)

        // If we fix the choice for ONE index, say i=0, we might propagate constraints.
        // However, the problem allows *any* j != i.

        // Let's simplify: For a target parity K, for each i, we must find a choice such that
        // nums2[i] % 2 == K.

        const possible = Array(n).fill(false);

        // Precalculate the parities of nums1
        const parities1 = nums1.map(x => Math.abs(x % 2));

        // Try to satisfy the condition for target parity K
        let success = true;
        let choices = Array(n).fill(null); // Stores the decision for nums2[i]: 0 (nums1[i]) or j (nums1[i] - nums1[j])

        // Since the choice of j can be anything, we check if *there exists* a choice for each i.

        for (let i = 0; i < n; i++) {
            let canSatisfy = false;

            // Option 1: nums2[i] = nums1[i]
            if (parities1[i] === K) {
                canSatisfy = true;
                // choices[i] = 0; // If we choose this, it satisfies K
            }

            // Option 2: nums2[i] = nums1[i] - nums1[j], j != i
            if (!canSatisfy) {
                for (let j = 0; j < n; j++) {
                    if (i === j) continue;

                    // Parity of nums1[i] - nums1[j] is parities1[i] XOR parities1[j]
                    const diffParity = parities1[i] ^ parities1[j];

                    if (diffParity === K) {
                        canSatisfy = true;
                        // choices[i] = j; // If we choose this, it satisfies K
                        break; 
                    }
                }
            }

            if (!canSatisfy) {
                success = false;
                break;
            }
        }

        if (success) {
            return true;
        }
    }

    return false;
}

