fun solve(nums1: Array<Long>): Boolean {
    val n = nums1.size

    // Helper to get parity (0 for even, 1 for odd)
    fun getParity(num: Long): Int {
        return (num % 2).toInt()
    }

    // Precalculate the parities of nums1
    val parities1 = IntArray(n) { getParity(nums1[it]) }

    // Iterate over all possible target parities K (0 for even, 1 for odd)
    for (K in 0..1) {
        var success = true

        // Try to satisfy the condition for target parity K for every element i
        for (i in 0 until n) {
            var canSatisfy = false

            // Option 1: nums2[i] = nums1[i]. Parity is parities1[i].
            if (parities1[i] == K) {
                canSatisfy = true
            }

            // Option 2: nums2[i] = nums1[i] - nums1[j], j != i. Parity is parities1[i] XOR parities1[j].
            if (!canSatisfy) {
                for (j in 0 until n) {
                    if (i == j) continue

                    // Parity of difference: P_i XOR P_j
                    val diffParity = parities1[i] xor parities1[j]

                    if (diffParity == K) {
                        canSatisfy = true
                        break // Found a suitable j for this i
                    }
                }
            }

            if (!canSatisfy) {
                success = false
                break // Cannot satisfy K for index i, so this target K fails
            }
        }

        if (success) {
            return true // Found a target parity K that is achievable for all elements
        }
    }

    return false
}
